// Time:  O(n)
// Space: O(1)

// string
class Solution {
public:
    int scoreOfString(string s) {
        int result = 0;
        for (int i = 0; i + 1 < size(s); ++i) {
            result += abs(s[i + 1] - s[i]);
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

# string
class Solution(object):
    def scoreOfString(self, s):
        """
        :type s: str
        :rtype: int
        """
        return sum(abs(ord(s[i+1])-ord(s[i])) for i in xrange(len(s)-1))
